<template>
    <view>
        <!-- 自定义顶部导航 -->
        <u-navbar title="メンバー管理" :placeholder="true" :safeAreaInsetTop="true"
            style="border-bottom: 2upx solid #FBFBFD;">
            <view class="u-nav-slot" slot="left">
                <image src="../../static/icons/tclose.png" style="width: 60upx;height: 60upx;" mode="" @click="goIndex">
                </image>
            </view>
            <view class="u-nav-slot" slot="right">
                <image src="../../static/icons/fillSetting.png" style="width: 60upx;height: 60upx;" @click="toSetting"
                    mode=""></image>
            </view>
        </u-navbar>
        <view class="con">
            <view class="search">
                <u--input placeholder="名前、電話番号、IDで検索" prefixIcon="search" prefixIconStyle="font-size: 22px;color: #aaa">
                </u--input>
            </view>
            <view class="total">
                メンバー数:{{array.length}}
            </view>
        </view>
        <view class="listContent">
            <u-swipe-action autoClose>
                <u-swipe-action-item v-for="(item,index) in array" :options="options1">
                    <view class="swipe-action u-border-top u-border-bottom">
                        <view class="swipe-action__content">
                            <view class="itemContent" @click="toDetail(item.uid)">
                                <view class="itemLeft">
                                    <image :src="item.avatar" mode=""></image>
                                </view>
                                <view class="itemRight">
                                    <view class="rightItem">
                                        <view class="userName" v-text="item.name"></view>
                                        <view class="mtime" v-text="showTimePipe(item.timestamp*1000)"></view>
                                    </view>
                                    <view class="rightItem">
                                        <view class="tel" v-if="item.type == 1" v-text="item.message"></view>
                                        <view class="tel" v-if="item.type == 2">[图片]</view>
                                        <view v-if="item.unread_num > 0" class="userId" v-text="item.unread_num"></view>
                                    </view>
                                </view>
                            </view>
                        </view>
                    </view>
                </u-swipe-action-item>
            </u-swipe-action>
        </view>
    </view>
</template>

<script>
    import {
        getMessageList
    } from "@/api/index.js"
    export default {
        data() {
            return {
                options1: [{
                    text: '削除',
                    style: {
                        backgroundColor: '#D93025'
                    }
                }],
                array: []
            }
        },
        computed: {
            newMessage() {
                return this.$store.state.newMessage;
            },
        },
        mounted() {
            console.log("mounted")
        },
        created() {
            console.log("created")
            this.getList()
        },
        watch: {
            newMessage: {
                handler(nval, oval) {
                    let that = this
                    console.log("new", nval); //nval改变后的新数据，oval改变前的旧数据
                    if(nval){
                        that.getList()
                    }
                },
                deep: true, // 深度监听
                immediate: true, //立即执行
            }
        },
        methods: {
            toDetail(id) {
                uni.navigateTo({
                    url: "../message/chat/chat?uid="+id
                })
            },
            toSetting() {
                uni.navigateTo({
                    url: "../message/setting/setting"
                })
            },
            goIndex() {
                uni.switchTab({
                    url: "../index/index"
                })
            },
            getList() {
                let that = this
                let data = {}
                data["type"] = "list"
                data["uid"] = 0
                data["mid"] = 0
                data["timestamp"] = 0
                getMessageList(data).then((res) => {
                    console.log(res)
                    if (res.code == 200) {
                        that.array = res.data.messages
                    }
                })
            },
            showTimePipe(unix_stamp) { // unix_stamp 精确到微秒
                var _today_obj = new Date(),
                    _today_date = {
                        y: _today_obj.getFullYear(),
                        m: (_today_obj.getMonth() + 1 < 10 ? '0' + (_today_obj.getMonth() - -1) : (_today_obj
                        .getMonth() - -1)),
                        d: (_today_obj.getDate() < 10 ? '0' + _today_obj.getDate() : _today_obj.getDate())
                    }

                var _today_stamp = Date.parse(_today_date.y + '/' + _today_date.m + '/' + _today_date.d + ' 00:00:00')

                var stamp = []
                stamp[0] = _today_stamp + 86400000
                stamp[1] = _today_stamp
                stamp[2] = _today_stamp - 86400000
                stamp[3] = _today_stamp - 172800000
                stamp[4] = _today_stamp - 518400000 // 7天
                stamp[5] = _today_stamp - 31536000000 // 365天
                var _compare_obj = new Date()
                _compare_obj.setTime(unix_stamp)
                var return_str
                if (unix_stamp >= stamp[1] && unix_stamp < stamp[0]) {
                    return_str = _compare_obj.getHours() + ':' + (_compare_obj.getMinutes() < 10 ? '0' + _compare_obj
                        .getMinutes() : _compare_obj.getMinutes())
                } else if (unix_stamp >= stamp[2] && unix_stamp < stamp[1]) {
                    var yesterdayText = '昨日'
                    return_str = yesterdayText + ' ' + _compare_obj.getHours() + ':' +
                        (_compare_obj.getMinutes() < 10 ? '0' + _compare_obj.getMinutes() : _compare_obj.getMinutes())
                } else if (unix_stamp >= stamp[3] && unix_stamp < stamp[2]) { // 7天内
                    var daynames = ['天', '一', '二', '三', '四', '五', '六']
                    var dathStr = '星期' + daynames[_compare_obj.getDay()]
                    var SundayText = '日'
                    var MondayText = '月'
                    var TuesdayText = '火'
                    var WednesdayText = '水'
                    var ThursdayText = '木'
                    var FridayText = '金'
                    var SaturdayText = '土'
                    var dathStr2
                    switch (dathStr) {
                        case '星期天':
                            dathStr2 = SundayText
                            break
                        case '星期一':
                            dathStr2 = MondayText
                            break
                        case '星期二':
                            dathStr2 = TuesdayText
                            break
                        case '星期三':
                            dathStr2 = WednesdayText
                            break
                        case '星期四':
                            dathStr2 = ThursdayText
                            break
                        case '星期五':
                            dathStr2 = FridayText
                            break
                        case '星期六':
                            dathStr2 = SaturdayText
                            break
                        default:
                            dathStr2 = dathStr
                            break
                    }
                    return_str = dathStr2 + ' ' + _compare_obj.getHours() + ':' +
                        (_compare_obj.getMinutes() < 10 ? '0' + _compare_obj.getMinutes() : _compare_obj.getMinutes())
                } else if (unix_stamp >= stamp[5] && unix_stamp < stamp[4]) { // 365天内
                    var monthText = '月'
                    var dayText = '日'
                    return_str = (_compare_obj.getMonth() - (-1)) + monthText + _compare_obj.getDate() + dayText + ' ' +
                        _compare_obj.getHours() + ':' + (_compare_obj.getMinutes() < 10 ? '0' + _compare_obj
                            .getMinutes() :
                            _compare_obj.getMinutes())

                } else {
                    var yearText = '年'
                    var monthText = '月'
                    var dayText = '日'
                    return_str = _compare_obj.getFullYear() + yearText + (_compare_obj.getMonth() - (-1)) +
                        monthText + _compare_obj.getDate() + dayText + ' ' + _compare_obj.getHours() + ':' +
                        (_compare_obj.getMinutes() < 10 ? '0' + _compare_obj.getMinutes() : _compare_obj.getMinutes())
                }
                return return_str

            }
        }
    }
</script>

<style lang="scss">
    .userName {
        font-size: 32upx;
        font-family: Hiragino Sans-W6, Hiragino Sans;
        font-weight: bold;
        color: #1D1D1F;
    }

    .userId {
        width: 60upx;
        height: 60upx;
        background: #D93025;
        text-align: center;
        line-height: 60upx;
        font-size: 32upx;
        font-family: Hiragino Sans-W6, Hiragino Sans;
        font-weight: normal;
        color: #FFFFFF;
        border-radius: 50%;
    }

    .listContent {
        box-sizing: border-box;
        padding: 5upx 32upx;
    }

    .tel {
        font-size: 28upx;
        font-family: Hiragino Sans-W3, Hiragino Sans;
        font-weight: normal;
        color: #707070;
        width: 502upx;
    }

    .mtime {
        font-size: 20upx;
        font-family: Hiragino Sans-W3, Hiragino Sans;
        font-weight: normal;
        color: #86868B;
    }

    .con {
        background-color: #f9f9f9;
        box-sizing: border-box;
        padding: 32upx;
        box-shadow: 0px 1upx 0px 2upx rgba(0, 0, 0, 0.3);

        .search {
            background: rgba(0, 0, 0, .05);

        }

        .total {
            margin-top: 32upx;
        }
    }

    .itemContent {
        display: flex;
        align-items: center;
        box-sizing: border-box;
        padding: 20upx 0;

        .itemLeft {
            width: 80upx;
            height: 80upx;
            margin-right: 20upx;
            flex-shrink: 0;

            image {
                width: 100%;
                height: 100%;
            }
        }

        .rightItem {
            display: flex;
            align-items: center;
            justify-content: space-between;
        }
    }
</style>
